using benchmark_clock = std::chrono::steady_clock;

static int get_base_parallelism() {
  static int value = -1;
  if (value < 0) {
    cudaDeviceProp prop{};
    cudaGetDeviceProperties(&prop, 0);
    value = prop.multiProcessorCount;
    if (value < 1) value = 1;
  }
  return value;
}

template <typename T>
struct DeviceScalarBuffer {
  static T* ptr() {
    static T* p = nullptr;
    if (!p) cudaMalloc(&p, sizeof(T));
    return p;
  }
};

__device__ inline void atomic_add_t(float* addr, float v) { atomicAdd(addr, v); }
__device__ inline void atomic_add_t(int* addr, int v) { atomicAdd(addr, v); }

__device__ inline void atomic_add_t(double* address, double val) {
#if __CUDA_ARCH__ >= 600
  atomicAdd(address, val);
#else
  unsigned long long int* address_as_ull = (unsigned long long int*)address;
  unsigned long long int old = *address_as_ull, assumed;
  do {
    assumed = old;
    old = atomicCAS(address_as_ull, assumed,
                    __double_as_longlong(val + __longlong_as_double(assumed)));
  } while (assumed != old);
#endif
}

template <typename Element, unsigned int compute_iterations>
__global__ void bench_kernel(size_t len, Element* src, Element* sum_out) {
  constexpr size_t static_chunk_size = 4096;
  size_t chunk = blockIdx.x;
  size_t num_chunks = len / static_chunk_size;
  if (chunk >= num_chunks) return;

  size_t base = chunk * static_chunk_size;

  Element f0 = src[base + 0];
  Element f1 = src[base + 1];
  Element f2 = src[base + 2];
  Element f3 = src[base + 3];
  Element f4 = src[base + 4];
  Element f5 = src[base + 5];
  Element f6 = src[base + 6];
  Element f7 = src[base + 7];

  Element local_sum = 0;

  for (size_t i = threadIdx.x; i < static_chunk_size; i += blockDim.x) {
    Element v = src[base + i];
    Element t0 = v, t1 = v, t2 = v, t3 = v, t4 = v, t5 = v, t6 = v, t7 = v;

    for (size_t j = 0; j < compute_iterations / 8; ++j) {
      t0 = t0 * t0 + f0;
      t1 = t1 * t1 + f1;
      t2 = t2 * t2 + f2;
      t3 = t3 * t3 + f3;
      t4 = t4 * t4 + f4;
      t5 = t5 * t5 + f5;
      t6 = t6 * t6 + f6;
      t7 = t7 * t7 + f7;
    }

    if (compute_iterations % 8 > 0) t0 = t0 * t0 + f0;
    if (compute_iterations % 8 > 1) t1 = t1 * t1 + f1;
    if (compute_iterations % 8 > 2) t2 = t2 * t2 + f2;
    if (3 < compute_iterations % 8) t3 = t3 * t3 + f3;
    if (4 < compute_iterations % 8) t4 = t4 * t4 + f4;
    if (5 < compute_iterations % 8) t5 = t5 * t5 + f5;
    if (6 < compute_iterations % 8) t6 = t6 * t6 + f6;

    local_sum += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
  }

  atomic_add_t(sum_out, local_sum);
}

template <typename Element>
__global__ void store_sum_kernel(Element* src, const Element* sum_out) {
  src[0] = sum_out[0];
}

template <typename Element, unsigned int compute_iterations>
size_t bench(size_t len, const Element /*seed1*/, const Element /*seed2*/, Element* src) {
  constexpr size_t static_chunk_size = 4096;
  size_t num_chunks = len / static_chunk_size;
  Element* d_sum = DeviceScalarBuffer<Element>::ptr();

  cudaMemset(d_sum, 0, sizeof(Element));

  const int block_size = 256;
  bench_kernel<Element, compute_iterations><<<static_cast<unsigned int>(num_chunks), block_size>>>(
      len, src, d_sum);
  store_sum_kernel<Element><<<1, 1>>>(src, d_sum);

  return len;
}

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = static_cast<int>(size / sizeof(double));
  auto x_2 = benchmark_clock::now();

  double* ptr = reinterpret_cast<double*>(c);
  bench<double, 16>(num_elements, 1., -1., ptr);
  cudaDeviceSynchronize();

  auto var_0 = benchmark_clock::now() - x_2;
  return std::chrono::duration_cast<std::chrono::microseconds>(var_0).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  cudaDeviceSynchronize();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename Op>
auto benchmark_omp(Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  auto duration = op();
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  if (get_base_parallelism() > 1) {
    for (int i = 1; i < total_half_thread_runs; i++) {
      duration = op();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t v_1, int compute_iterations)
      : memory_space_{v_1}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, static_cast<int>(compute_iterations)};

  float* c_as_float = reinterpret_cast<float*>(c);
  auto kernel_time_mad_sp = benchmark_omp([&] {
    return measure_operation([&] {
      bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f, c_as_float);
    });
  });

  double* c_as_double = reinterpret_cast<double*>(c);
  auto kernel_time_mad_dp = benchmark_omp([&] {
    return measure_operation([&] {
      bench<double, compute_iterations>(cs.element_count<double>(), 1., -1., c_as_double);
    });
  });

  int* c_as_int = reinterpret_cast<int*>(c);
  auto kernel_time_mad_int = benchmark_omp([&] {
    return measure_operation([&] {
      bench<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp * 1000. /
                   (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp * 1000. /
                   (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int * 1000. /
                   (1000. * 1000. * 1000.)

            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* cd, size_t size) {
  runbench<compute_iterations>(cd, size);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* cd, size_t size) {
  runbench_range<j1>(cd, size);
  runbench_range<j2, Args...>(cd, size);
}

